/// <summary>
/// Represents the quality contract table for the ETGSPAIN model.
/// </summary>
public class ETGSPAINPurchContractQualityTable extends common
{
}

Method.Source:
/// <summary>
/// Finds a record in the ETGSPAINPurchContractQualityTable.
/// </summary>
/// <param name="_qualityOperation">The quality operation ID.</param>
/// <param name="_forUpdate">Specifies if the record should be locked for update.</param>
/// <returns>Returns the found ETGSPAINPurchContractQualityTable record.</returns>
static ETGSPAINPurchContractQualityTable find(   ETGSPAINQualityOperationId    _qualityOperation,
                                        boolean                 _forUpdate = false)
{
    ETGSPAINPurchContractQualityTable contractQualityTable;

    if (_qualityOperation)
    {
        if (_forUpdate)
        {
            contractQualityTable.selectForUpdate(_forUpdate);
        }

        select firstonly contractQualityTable
            index hint QualityOperationIdx
            where contractQualityTable.QualityOperation == _qualityOperation;
    }

    return contractQualityTable;
}

/// <summary>
/// Checks if a record exists in the ETGSPAINPurchContractQualityTable.
/// </summary>
/// <param name="_qualityOperation">The quality operation ID.</param>
/// <returns>Returns true if the record exists, otherwise false.</returns>
static boolean exist(ETGSPAINQualityOperationId  _qualityOperation)
{
    return _qualityOperation && (select firstonly RecId from ETGSPAINPurchContractQualityTable
                                index hint QualityOperationIdx
                                where ETGSPAINPurchContractQualityTable.QualityOperation == _qualityOperation).RecId != 0;
}
